def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        base_score = 0
        if ratio > 2:
            base_score = 2000 + 50 * (ratio - 2) ** 3
        elif ratio > 1:
            base_score = 1000 + 20 * (ratio - 1) ** 2
        else:
            if ratio > 0.9:
                base_score = 80 * ratio + 15
            elif ratio > 0.7:
                base_score = 50 * ratio + 10
            elif ratio > 0.4:
                base_score = 20 * ratio + 5
            else:
                base_score = 5 * ratio
            if capacity < 5:
                base_score += 20
            elif capacity < 20:
                base_score += 10
            elif capacity > 200:
                base_score -= 15
        modifier = 1.0
        if i % 3 == 0:
            modifier += 0.15
            if ratio < 0.5:
                modifier += 0.05
        elif i % 3 == 1:
            modifier -= 0.1
            if ratio > 1.5:
                modifier -= 0.05
        else:
            modifier += 0.05
            if capacity % 2 == 0:
                modifier += 0.03
        adjusted_score = base_score * modifier
        if i % 5 == 0:
            sum_neighbors = 0
            count = 0
            for j in range(max(0, i-2), min(len(bins), i+3)):
                if j != i and bins[j] > 0:
                    sum_neighbors += abs(item - bins[j])
                    count += 1
            if count > 0:
                avg_diff = sum_neighbors / count
                if avg_diff < capacity * 0.5:
                    adjusted_score *= 0.8
                else:
                    adjusted_score *= 1.2
        priorities[i] = adjusted_score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fallback = 0
    else:
        fallback = np.min(finite_priorities)
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = fallback + 150
    for i in range(len(priorities)):
        if priorities[i] < 20:
            priorities[i] += 10 * (item / (bins[i] + 1))
    return priorities
